/** Msg defines the Msg service. */
export interface Msg {
  UpdateParams(request: MsgUpdateParams): Promise<MsgUpdateParamsResponse>;
  /** Emite um certificado vinculado a um merchant_id. */
  IssueCertificate(request: MsgIssueCertificate): Promise<MsgIssueCertificateResponse>;
  /** Transfere propriedade de um certificado. */
  TransferCertificate(request: MsgTransferCertificate): Promise<MsgTransferCertificateResponse>;
  /** Adiciona um registro de serviço/manutenção. */
  AddServiceRecord(request: MsgAddServiceRecord): Promise<MsgAddServiceRecordResponse>;
  /** Revoga um certificado (apenas emissor/merchant owner). */
  RevokeCertificate(request: MsgRevokeCertificate): Promise<MsgRevokeCertificateResponse>;
}

export const MsgServiceName = "byx.certificados.v1.Msg";
export class MsgClientImpl implements Msg {
  private readonly rpc: Rpc;
  private readonly service: string;
  constructor(rpc: Rpc, opts?: { service?: string }) {
    this.service = opts?.service || MsgServiceName;
    this.rpc = rpc;
    this.UpdateParams = this.UpdateParams.bind(this);
    this.IssueCertificate = this.IssueCertificate.bind(this);
    this.TransferCertificate = this.TransferCertificate.bind(this);
    this.AddServiceRecord = this.AddServiceRecord.bind(this);
    this.RevokeCertificate = this.RevokeCertificate.bind(this);
  }
  UpdateParams(request: MsgUpdateParams): Promise<MsgUpdateParamsResponse> {
    const data = MsgUpdateParams.encode(request).finish();
    const promise = this.rpc.request(this.service, "UpdateParams", data);
    return promise.then((data) => MsgUpdateParamsResponse.decode(new BinaryReader(data)));
  }

  IssueCertificate(request: MsgIssueCertificate): Promise<MsgIssueCertificateResponse> {
    const data = MsgIssueCertificate.encode(request).finish();
    const promise = this.rpc.request(this.service, "IssueCertificate", data);
    return promise.then((data) => MsgIssueCertificateResponse.decode(new BinaryReader(data)));
  }

  TransferCertificate(request: MsgTransferCertificate): Promise<MsgTransferCertificateResponse> {
    const data = MsgTransferCertificate.encode(request).finish();
    const promise = this.rpc.request(this.service, "TransferCertificate", data);
    return promise.then((data) => MsgTransferCertificateResponse.decode(new BinaryReader(data)));
  }

  AddServiceRecord(request: MsgAddServiceRecord): Promise<MsgAddServiceRecordResponse> {
    const data = MsgAddServiceRecord.encode(request).finish();
    const promise = this.rpc.request(this.service, "AddServiceRecord", data);
    return promise.then((data) => MsgAddServiceRecordResponse.decode(new BinaryReader(data)));
  }

  RevokeCertificate(request: MsgRevokeCertificate): Promise<MsgRevokeCertificateResponse> {
    const data = MsgRevokeCertificate.encode(request).finish();
    const promise = this.rpc.request(this.service, "RevokeCertificate", data);
    return promise.then((data) => MsgRevokeCertificateResponse.decode(new BinaryReader(data)));
  }
}

interface Rpc {
  request(service: string, method: string, data: Uint8Array): Promise<Uint8Array>;
}

type Builtin = Date | Function | Uint8Array | string | number | boolean | undefined;

export type DeepPartial<T> = T extends Builtin ? T
  : T extends globalThis.Array<infer U> ? globalThis.Array<DeepPartial<U>>
  : T extends ReadonlyArray<infer U> ? ReadonlyArray<DeepPartial<U>>
  : T extends {} ? { [K in keyof T]?: DeepPartial<T[K]> }
  : Partial<T>;

type KeysOfUnion<T> = T extends T ? keyof T : never;
export type Exact<P, I extends P> = P extends Builtin ? P
  : P & { [K in keyof P]: Exact<P[K], I[K]> } & { [K in Exclude<keyof I, KeysOfUnion<P>>]: never };

function longToNumber(int64: { toString(): string }): number {
  const num = globalThis.Number(int64.toString());
  if (num > globalThis.Number.MAX_SAFE_INTEGER) {
    throw new globalThis.Error("Value is larger than Number.MAX_SAFE_INTEGER");
  }
  if (num < globalThis.Number.MIN_SAFE_INTEGER) {
    throw new globalThis.Error("Value is smaller than Number.MIN_SAFE_INTEGER");
  }
  return num;
}

function isSet(value: any): boolean {
  return value !== null && value !== undefined;
}

export interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
  fromJSON(object: any): T;
  toJSON(message: T): unknown;
  create<I extends Exact<DeepPartial<T>, I>>(base?: I): T;
  fromPartial<I extends Exact<DeepPartial<T>, I>>(object: I): T;
}
